const items = $input.all();
const tradesItem = items.find(i => Array.isArray(i.json) || (i.json && i.json.id !== undefined && i.json.price !== undefined));
const tickerItem = items.find(i => i.json && i.json.symbol === 'BTCUSDT');
const trades = Array.isArray(tradesItem?.json) ? tradesItem.json : (tradesItem?.json ? [tradesItem.json] : []);
const ticker = tickerItem?.json || {};
const buyCount = trades.filter(t => !t.isBuyerMaker).length;
const sellCount = trades.filter(t => t.isBuyerMaker).length;
const prices = trades.slice(0, 20).map(t => parseFloat(t.price));
const avgPrice = prices.length ? (prices.reduce((a,b)=>a+b,0)/prices.length).toFixed(2) : ticker.lastPrice || 'N/A';
const summary = {
  symbol: 'BTCUSDT',
  tradesCount: trades.length,
  buyCount,
  sellCount,
  avgPrice,
  lastPrice: ticker.lastPrice,
  priceChangePercent: ticker.priceChangePercent,
  volume: ticker.volume,
  high24h: ticker.highPrice,
  low24h: ticker.lowPrice
};
return [{ json: summary }];

